import { supabase } from '../supabaseClient';

export async function fetchClipLikeSummary(clipId, websiteUserId = '') {
  const clipIdNum = Number(clipId);
  if (!Number.isFinite(clipIdNum)) {
    return { clipId: String(clipId || ''), likeCount: 0, liked: false };
  }

  const { count } = await supabase
    .from('clip_likes')
    .select('*', { count: 'exact', head: true })
    .eq('clip_id', clipIdNum);

  let liked = false;
  if (websiteUserId) {
    const { data } = await supabase
      .from('clip_likes')
      .select('id')
      .eq('clip_id', clipIdNum)
      .eq('user_id', websiteUserId)
      .maybeSingle();
    liked = Boolean(data);
  }

  return { clipId: String(clipId || ''), likeCount: count || 0, liked };
}

export async function setClipLikePreference(clipId, shouldLike) {
  const clipIdNum = Number(clipId);
  if (!Number.isFinite(clipIdNum)) {
    throw new Error('Invalid clip ID');
  }

  const { data: userData } = await supabase.auth.getUser();
  const userId = userData?.user?.id;
  if (!userId) {
    throw new Error('Sign in to continue.');
  }

  if (shouldLike) {
    const { error } = await supabase
      .from('clip_likes')
      .insert({ clip_id: clipIdNum, user_id: userId })
      .maybeSingle();
    if (error && !error.message?.includes('duplicate')) {
      throw error;
    }
  } else {
    const { error } = await supabase
      .from('clip_likes')
      .delete()
      .eq('clip_id', clipIdNum)
      .eq('user_id', userId);
    if (error) throw error;
  }

  const { count } = await supabase
    .from('clip_likes')
    .select('*', { count: 'exact', head: true })
    .eq('clip_id', clipIdNum);

  return { liked: shouldLike, likeCount: count || 0 };
}

export async function fetchClipComments(clipId, limit = 24) {
  const clipIdNum = Number(clipId);
  if (!Number.isFinite(clipIdNum)) {
    return { clipId: String(clipId || ''), commentCount: 0, comments: [] };
  }

  const { data, error } = await supabase
    .from('clip_comments')
    .select('*')
    .eq('clip_id', clipIdNum)
    .order('created_at', { ascending: false })
    .limit(limit);

  if (error) throw error;

  return {
    clipId: String(clipId || ''),
    commentCount: data?.length || 0,
    comments: (data || []).map((c) => ({
      ...c,
      user_id: c.user_id,
      body: c.body,
      created_at: c.created_at
    }))
  };
}

export async function postClipComment(clipId, body) {
  const clipIdNum = Number(clipId);
  if (!Number.isFinite(clipIdNum)) {
    throw new Error('Invalid clip ID');
  }

  const { data: userData, error: userError } = await supabase.auth.getUser();
  if (userError || !userData?.user?.id) {
    throw new Error('Sign in to continue.');
  }

  const { data, error } = await supabase
    .from('clip_comments')
    .insert({
      clip_id: clipIdNum,
      user_id: userData.user.id,
      body
    })
    .select()
    .single();

  if (error) throw error;

  return { comment: data, commentCount: 0 };
}

