const CSS_TEMPLATES = [
  {
    id: 'macclipper-default',
    label: 'MacClipper Default',
    css: MACCLIPPER_DEFAULT_CSS,
  },
];

function makeId() {
  return Math.random().toString(36).substring(2, 10);
}

function buildEmailHtml({ blocks, cssTemplate, subject }) {
  const headerBlock = blocks.find((b) => b.type === 'header') || {
    type: 'header',
    iconUrl: DEFAULT_ICON_URL,
    badge: 'MacClipper',
    title: subject || 'New Update',
    subtitle: '',
  };
  const bodyBlocks = blocks.filter((b) => b.type !== 'header');

  const bodyHtml = bodyBlocks.map((block) => {
    switch (block.type) {
      case 'text':
        return `<div style="margin-bottom:16px;">${block.content.replace(/\n/g, '<br/>')}</div>`;
      case 'image':
        return block.url
          ? `<div style="margin-bottom:16px;"><img src="${block.url}" alt="${block.alt || ''}" style="max-width:100%;border-radius:12px;" /></div>`
          : '';
      case 'button':
        return block.url && block.label
          ? `<div class="email-button"><a href="${block.url}">${block.label}</a></div>`
          : '';
      case 'divider':
        return '<hr style="border:none;border-top:1px solid rgba(255,198,92,0.2);margin:24px 0;" />';
      default:
        return '';
    }
  }).join('\n');

  return `<!doctype html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>${subject || 'MacClipper'}</title>
  <style>${cssTemplate || MACCLIPPER_DEFAULT_CSS}</style>
</head>
<body>
  <table role="presentation" width="100%" cellspacing="0" cellpadding="0" class="email-wrapper">
    <tr>
      <td align="center">
        <table role="presentation" width="100%" cellspacing="0" cellpadding="0" class="email-container">
          <tr>
            <td class="email-header">
              ${headerBlock.iconUrl ? `<img src="${headerBlock.iconUrl}" alt="MacClipper" width="72" height="72" />` : ''}
              ${headerBlock.badge ? `<div class="badge">${headerBlock.badge}</div>` : ''}
              ${headerBlock.title ? `<h1>${headerBlock.title}</h1>` : ''}
              ${headerBlock.subtitle ? `<p>${headerBlock.subtitle}</p>` : ''}
            </td>
          </tr>
          <tr>
            <td class="email-body">
              ${bodyHtml}
            </td>
          </tr>
        </table>
      </td>
    </tr>
  </table>
</body>
</html>`;
}

function BlockEditor({ block, onChange, onDelete }) {
  switch (block.type) {
    case 'header':
      return (
        <div className="space-y-2 rounded-lg border border-border bg-card p-3">
          <div className="flex items-center justify-between">
            <span className="text-xs font-semibold text-muted-foreground">HEADER</span>
            <button type="button" onClick={onDelete} className="text-red-500 hover:text-red-400"><Trash2 className="h-3 w-3" /></button>
          </div>
          <input
            type="text"
            value={block.title || ''}
            onChange={(e) => onChange({ ...block, title: e.target.value })}
            placeholder="Title"
            className="w-full rounded border border-border bg-background px-2 py-1 text-sm text-foreground"
          />
          <input
            type="text"
            value={block.subtitle || ''}
            onChange={(e) => onChange({ ...block, subtitle: e.target.value })}
            placeholder="Subtitle (optional)"
            className="w-full rounded border border-border bg-background px-2 py-1 text-sm text-foreground"
          />
          <input
            type="text"
            value={block.iconUrl || ''}
            onChange={(e) => onChange({ ...block, iconUrl: e.target.value })}
            placeholder="Icon URL"
            className="w-full rounded border border-border bg-background px-2 py-1 text-sm text-foreground"
          />
          <input
            type="text"
            value={block.badge || ''}
            onChange={(e) => onChange({ ...block, badge: e.target.value })}
            placeholder="Badge text (e.g. MacClipper Pro)"
            className="w-full rounded border border-border bg-background px-2 py-1 text-sm text-foreground"
          />
        </div>
      );
    case 'text':
      return (
        <div className="space-y-2 rounded-lg border border-border bg-card p-3">
          <div className="flex items-center justify-between">
            <span className="text-xs font-semibold text-muted-foreground">TEXT</span>
            <button type="button" onClick={onDelete} className="text-red-500 hover:text-red-400"><Trash2 className="h-3 w-3" /></button>
          </div>
          <textarea
            value={block.content || ''}
            onChange={(e) => onChange({ ...block, content: e.target.value })}
            placeholder="Enter text content..."
            rows={4}
            className="w-full rounded border border-border bg-background px-2 py-1 text-sm text-foreground"
          />
        </div>
      );
    case 'image':
      return (
        <div className="space-y-2 rounded-lg border border-border bg-card p-3">
          <div className="flex items-center justify-between">
            <span className="text-xs font-semibold text-muted-foreground">IMAGE</span>
            <button type="button" onClick={onDelete} className="text-red-500 hover:text-red-400"><Trash2 className="h-3 w-3" /></button>
          </div>
          <input
            type="text"
            value={block.url || ''}
            onChange={(e) => onChange({ ...block, url: e.target.value })}
            placeholder="Image URL"
            className="w-full rounded border border-border bg-background px-2 py-1 text-sm text-foreground"
          />
          <input
            type="text"
            value={block.alt || ''}
            onChange={(e) => onChange({ ...block, alt: e.target.value })}
            placeholder="Alt text"
            className="w-full rounded border border-border bg-background px-2 py-1 text-sm text-foreground"
          />
          {block.url && (
            <img src={block.url} alt="" className="max-h-32 rounded object-contain" onError={(e) => { e.target.style.display = 'none'; }} />
          )}
        </div>
      );
    case 'button':
      return (
        <div className="space-y-2 rounded-lg border border-border bg-card p-3">
          <div className="flex items-center justify-between">
            <span className="text-xs font-semibold text-muted-foreground">BUTTON</span>
            <button type="button" onClick={onDelete} className="text-red-500 hover:text-red-400"><Trash2 className="h-3 w-3" /></button>
          </div>
          <input
            type="text"
            value={block.label || ''}
            onChange={(e) => onChange({ ...block, label: e.target.value })}
            placeholder="Button label"
            className="w-full rounded border border-border bg-background px-2 py-1 text-sm text-foreground"
          />
          <input
            type="text"
            value={block.url || ''}
            onChange={(e) => onChange({ ...block, url: e.target.value })}
            placeholder="Button URL"
            className="w-full rounded border border-border bg-background px-2 py-1 text-sm text-foreground"
          />
        </div>
      );
    case 'divider':
      return (
        <div className="flex items-center justify-between rounded-lg border border-border bg-card p-3">
          <span className="text-xs font-semibold text-muted-foreground">DIVIDER</span>
          <button type="button" onClick={onDelete} className="text-red-500 hover:text-red-400"><Trash2 className="h-3 w-3" /></button>
        </div>
      );
    default:
      return null;
  }
}

export default function AdminEmailCampaign({ resolveAccessToken }) {
  const [subject, setSubject] = useState('');
  const [recipients, setRecipients] = useState('all');
  const [templateId, setTemplateId] = useState('macclipper-default');
  const [blocks, setBlocks] = useState([
    { id: makeId(), type: 'header', iconUrl: DEFAULT_ICON_URL, badge: 'MacClipper', title: '', subtitle: '' },
    { id: makeId(), type: 'text', content: '' },
  ]);
  const [attachments, setAttachments] = useState([]);
  const [showPreview, setShowPreview] = useState(false);
  const [sending, setSending] = useState(false);
  const [sendResult, setSendResult] = useState(null);
  const [sendError, setSendError] = useState('');
  const fileInputRef = useRef(null);

  const cssTemplate = CSS_TEMPLATES.find((t) => t.id === templateId)?.css || MACCLIPPER_DEFAULT_CSS;

  const updateBlock = useCallback((id, updated) => {
    setBlocks((prev) => prev.map((b) => (b.id === id ? updated : b)));
  }, []);

  const deleteBlock = useCallback((id) => {
    setBlocks((prev) => prev.filter((b) => b.id !== id));
  }, []);

  const addBlock = useCallback((type) => {
    const block = { id: makeId(), type };
    if (type === 'text') block.content = '';
    if (type === 'image') block.url = '';
    if (type === 'button') block.label = '';
    if (type === 'header') {
      block.iconUrl = DEFAULT_ICON_URL;
      block.badge = 'MacClipper';
      block.title = '';
      block.subtitle = '';
    }
    setBlocks((prev) => [...prev, block]);
  }, []);

  const handleFileDrop = useCallback((e) => {
    e.preventDefault();
    const files = Array.from(e.dataTransfer?.files || e.target?.files || []);
    const readers = files.map((file) => new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = () => resolve({ name: file.name, type: file.type, data: reader.result.split(',')[1] });
      reader.readAsDataURL(file);
    }));
    Promise.all(readers).then((results) => {
      setAttachments((prev) => [...prev, ...results]);
    });
  }, []);

  const removeAttachment = useCallback((index) => {
    setAttachments((prev) => prev.filter((_, i) => i !== index));
  }, []);

  const htmlBody = buildEmailHtml({ blocks, cssTemplate, subject });

  async function handleSend() {
    if (!subject.trim()) { setSendError('Subject is required.'); return; }
    setSending(true);
    setSendResult(null);
    setSendError('');
    try {
      const token = (await resolveAccessToken())?.accessToken;
      if (!token) throw new Error('Not authenticated.');

      const res = await fetch(buildCloudAPIURL('/admin/send-email'), {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          recipients: recipients === 'all' ? 'all' : recipients.split(',').map((e) => e.trim()).filter(Boolean),
          subject: subject.trim(),
          htmlBody,
          textBody: blocks.filter((b) => b.type === 'text').map((b) => b.content).join('\n\n'),
          images: attachments.map((a) => ({
            filename: a.name,
            contentBase64: a.data,
            cid: a.name.replace(/[^a-zA-Z0-9]/g, '_'),
          })),
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || `Send failed (${res.status})`);
      setSendResult(data);
    } catch (err) {
      setSendError(err.message);
    } finally {
      setSending(false);
    }
  }

  return (
    <div className="space-y-5">
      <div className="flex items-center gap-3">
        <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary/10">
          <Mail className="h-5 w-5 text-primary" />
        </div>
        <div>
          <h3 className="text-lg font-bold text-foreground">Email Campaign</h3>
          <p className="text-sm text-muted-foreground">Compose and send bulk email to MacClipper users.</p>
        </div>
      </div>

      <div className="grid gap-5 lg:grid-cols-2">
        {/* Editor */}
        <div className="space-y-4">
          {/* Subject */}
          <div>
            <label className="mb-1 block text-xs font-medium text-muted-foreground">Subject</label>
            <input
              type="text"
              value={subject}
              onChange={(e) => setSubject(e.target.value)}
              placeholder="Email subject line"
              className="w-full rounded-lg border border-border bg-card px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none"
            />
          </div>

          {/* Recipients */}
          <div>
            <label className="mb-1 block text-xs font-medium text-muted-foreground">Recipients</label>
            <input
              type="text"
              value={recipients}
              onChange={(e) => setRecipients(e.target.value)}
              placeholder='Type "all" or comma-separated emails'
              className="w-full rounded-lg border border-border bg-card px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none"
            />
            <p className="mt-1 text-xs text-muted-foreground">Enter <strong>all</strong> to send to every registered user, or type specific email addresses separated by commas.</p>
          </div>

          {/* CSS Template */}
          <div>
            <label className="mb-1 block text-xs font-medium text-muted-foreground">CSS Template</label>
            <select
              value={templateId}
              onChange={(e) => setTemplateId(e.target.value)}
              className="w-full rounded-lg border border-border bg-card px-3 py-2 text-sm text-foreground focus:border-primary focus:outline-none"
            >
              {CSS_TEMPLATES.map((t) => (
                <option key={t.id} value={t.id}>{t.label}</option>
              ))}
            </select>
          </div>

          {/* Content Blocks */}
          <div>
            <label className="mb-1 block text-xs font-medium text-muted-foreground">Content Blocks</label>
            <div className="space-y-2">
              {blocks.map((block) => (
                <BlockEditor key={block.id} block={block} onChange={(updated) => updateBlock(block.id, updated)} onDelete={() => deleteBlock(block.id)} />
              ))}
            </div>
          </div>

          {/* Add Block Buttons */}
          <div className="flex flex-wrap gap-2">
            <button type="button" onClick={() => addBlock('text')} className="inline-flex items-center gap-1 rounded-lg border border-border px-3 py-1.5 text-xs font-medium text-foreground transition-colors hover:bg-muted">
              <Type className="h-3 w-3" /> Text
            </button>
            <button type="button" onClick={() => addBlock('image')} className="inline-flex items-center gap-1 rounded-lg border border-border px-3 py-1.5 text-xs font-medium text-foreground transition-colors hover:bg-muted">
              <ImageIcon className="h-3 w-3" /> Image
            </button>
            <button type="button" onClick={() => addBlock('button')} className="inline-flex items-center gap-1 rounded-lg border border-border px-3 py-1.5 text-xs font-medium text-foreground transition-colors hover:bg-muted">
              <Link2 className="h-3 w-3" /> Button
            </button>
            <button type="button" onClick={() => addBlock('divider')} className="inline-flex items-center gap-1 rounded-lg border border-border px-3 py-1.5 text-xs font-medium text-foreground transition-colors hover:bg-muted">
              <Plus className="h-3 w-3" /> Divider
            </button>
          </div>

          {/* File Attachments */}
          <div>
            <label className="mb-1 block text-xs font-medium text-muted-foreground">File Attachments</label>
            <div
              onDrop={handleFileDrop}
              onDragOver={(e) => e.preventDefault()}
              onClick={() => fileInputRef.current?.click()}
              className="cursor-pointer rounded-lg border-2 border-dashed border-border bg-card p-4 text-center transition-colors hover:border-primary"
            >
              <Upload className="mx-auto mb-1 h-5 w-5 text-muted-foreground" />
              <p className="text-xs text-muted-foreground">Drop files here or click to upload</p>
              <input
                ref={fileInputRef}
                type="file"
                multiple
                onChange={handleFileDrop}
                className="hidden"
              />
            </div>
            {attachments.length > 0 && (
              <div className="mt-2 space-y-1">
                {attachments.map((att, i) => (
                  <div key={i} className="flex items-center justify-between rounded-lg border border-border bg-card px-3 py-2">
                    <div className="flex items-center gap-2">
                      <File className="h-4 w-4 text-muted-foreground" />
                      <span className="text-xs text-foreground">{att.name}</span>
                    </div>
                    <button type="button" onClick={() => removeAttachment(i)} className="text-red-500 hover:text-red-400">
                      <Trash2 className="h-3 w-3" />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Preview */}
        <div>
          <div className="mb-2 flex items-center justify-between">
            <label className="text-xs font-medium text-muted-foreground">Preview</label>
            <button
              type="button"
              onClick={() => setShowPreview(!showPreview)}
              className="inline-flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground"
            >
              {showPreview ? <EyeOff className="h-3 w-3" /> : <Eye className="h-3 w-3" />}
              {showPreview ? 'Hide' : 'Show'}
            </button>
          </div>
          <div className="overflow-hidden rounded-lg border border-border">
            {showPreview ? (
              <iframe
                title="Email Preview"
                srcDoc={htmlBody}
                className="h-[600px] w-full bg-white"
                sandbox="allow-same-origin"
              />
            ) : (
              <div className="flex h-[600px] items-center justify-center bg-muted text-xs text-muted-foreground">
                Click "Show" to preview
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Actions */}
      <div className="flex items-center gap-3">
        <button
          type="button"
          onClick={handleSend}
          disabled={sending || !subject.trim()}
          className="inline-flex items-center gap-2 rounded-lg bg-primary px-5 py-2.5 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:opacity-60"
        >
          {sending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
          {sending ? 'Sending...' : 'Send Email'}
        </button>
      </div>

      {/* Send Result */}
      {sendError && (
        <div className="flex items-start gap-2 rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700 dark:border-red-800 dark:bg-red-950 dark:text-red-300">
          <AlertCircle className="mt-0.5 h-4 w-4 shrink-0" />
          <span>{sendError}</span>
        </div>
      )}
      {sendResult && (
        <div className="rounded-lg border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-700 dark:border-emerald-800 dark:bg-emerald-950 dark:text-emerald-300">
          <div className="flex items-center gap-2 font-medium">
            <CheckCircle className="h-4 w-4" />
            Email sent
          </div>
          <p className="mt-1">Sent: <strong>{sendResult.sent}</strong>, Failed: <strong>{sendResult.failed}</strong></p>
          {sendResult.errors?.length > 0 && (
            <details className="mt-2">
              <summary className="cursor-pointer text-xs">Show errors ({sendResult.errors.length})</summary>
              <ul className="mt-1 max-h-32 space-y-0.5 overflow-y-auto text-xs">
                {sendResult.errors.map((err, i) => <li key={i} className="text-red-600">{err}</li>)}
              </ul>
            </details>
          )}
        </div>
      )}
    </div>
  );
}
