import React, { useState } from 'react';
import { Shield, CheckCircle, XCircle, Loader2, Crown } from 'lucide-react';
import { buildCloudAPIURL } from '../lib/appRuntime';

const DEFAULT_ICON_URL = 'https://media.base44.com/images/public/user_69840c94143af1fbc044bd6f/cf2d115fa_AppIcon_1024x1024x32.png';

export default function AdminProGrant({ resolveAccessToken }) {
  const [appUuid, setAppUuid] = useState('');
  const [busy, setBusy] = useState('');
  const [result, setResult] = useState(null);
  const [error, setError] = useState('');

  async function handleGrant() {
    const uuid = appUuid.trim();
    if (!uuid) { setError('Enter an app UUID.'); return; }
    setBusy('grant');
    setResult(null);
    setError('');
    try {
      const token = (await resolveAccessToken())?.accessToken;
      if (!token) throw new Error('Not authenticated.');
      const res = await fetch(buildCloudAPIURL('/admin/grant-pro'), {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ appUuid: uuid }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || `Request failed (${res.status})`);
      setResult({ ok: true, ...data });
    } catch (err) {
      setError(err.message);
    } finally {
      setBusy('');
    }
  }

  async function handleRevoke() {
    const uuid = appUuid.trim();
    if (!uuid) { setError('Enter an app UUID.'); return; }
    if (!window.confirm(`Revoke Pro from ${uuid}? This also locks billing sync.`)) return;
    setBusy('revoke');
    setResult(null);
    setError('');
    try {
      const token = (await resolveAccessToken())?.accessToken;
      if (!token) throw new Error('Not authenticated.');
      const res = await fetch(buildCloudAPIURL('/admin/revoke-pro'), {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ appUuid: uuid }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || `Request failed (${res.status})`);
      setResult({ ok: true, action: 'revoked', ...data });
    } catch (err) {
      setError(err.message);
    } finally {
      setBusy('');
    }
  }

  return (
    <div className="space-y-5">
      <div className="flex items-center gap-3">
        <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-amber-500/10">
          <Crown className="h-5 w-5 text-amber-500" />
        </div>
        <div>
          <h3 className="text-lg font-bold text-foreground">Grant / Revoke Pro</h3>
          <p className="text-sm text-muted-foreground">Manage Pro entitlements by app UUID.</p>
        </div>
      </div>

      <div className="flex flex-wrap items-end gap-3">
        <div className="min-w-[320px] flex-1">
          <label className="mb-1 block text-xs font-medium text-muted-foreground">App UUID</label>
          <input
            type="text"
            value={appUuid}
            onChange={(e) => setAppUuid(e.target.value)}
            placeholder="xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx"
            className="w-full rounded-lg border border-border bg-card px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground focus:border-primary focus:outline-none"
          />
        </div>
        <button
          type="button"
          onClick={handleGrant}
          disabled={busy === 'grant'}
          className="inline-flex items-center gap-2 rounded-lg bg-emerald-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-emerald-700 disabled:opacity-60"
        >
          {busy === 'grant' ? <Loader2 className="h-4 w-4 animate-spin" /> : <CheckCircle className="h-4 w-4" />}
          Grant Pro
        </button>
        <button
          type="button"
          onClick={handleRevoke}
          disabled={busy === 'revoke'}
          className="inline-flex items-center gap-2 rounded-lg bg-red-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-red-700 disabled:opacity-60"
        >
          {busy === 'revoke' ? <Loader2 className="h-4 w-4 animate-spin" /> : <XCircle className="h-4 w-4" />}
          Revoke Pro
        </button>
      </div>

      {error && (
        <div className="rounded-lg border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700 dark:border-red-800 dark:bg-red-950 dark:text-red-300">
          {error}
        </div>
      )}

      {result && result.ok && (
        <div className="rounded-lg border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-700 dark:border-emerald-800 dark:bg-emerald-950 dark:text-emerald-300">
          <div className="flex items-center gap-2 font-medium">
            <CheckCircle className="h-4 w-4" />
            {result.action === 'revoked' ? 'Pro revoked' : 'Pro granted'}
          </div>
          {result.user && (
            <div className="mt-2 space-y-1">
              {result.user.subscriptionTier && <p>Tier: <strong>{result.user.subscriptionTier}</strong></p>}
              {result.user.paidFeatures?.length > 0 && <p>Features: <strong>{result.user.paidFeatures.join(', ')}</strong></p>}
              {result.user.accountStatus && <p>Status: <strong>{result.user.accountStatus}</strong></p>}
              {result.activationURL && (
                <p className="mt-2">
                  <a href={result.activationURL} className="underline">macclipper:// activation link</a>
                </p>
              )}
            </div>
          )}
        </div>
      )}

      <div className="mt-6 rounded-lg border border-border bg-card p-4">
        <h4 className="mb-2 text-sm font-semibold text-foreground">How it works</h4>
        <ul className="space-y-1 text-xs text-muted-foreground">
          <li>• <strong>Grant Pro</strong> adds the <code className="rounded bg-muted px-1">4k-pro</code> feature flag to the app installation or linked user.</li>
          <li>• <strong>Revoke Pro</strong> removes the flag and locks billing sync so Stripe cannot re-grant it.</li>
          <li>• To re-enable billing sync after revoke, Grant Pro again — this clears the lock.</li>
          <li>• If the app UUID does not exist yet, Grant Pro creates a placeholder installation.</li>
        </ul>
      </div>
    </div>
  );
}
