import { useState, useEffect } from "react";

const PASSWORD_HASH = "28e4e5b30ddef2b8e315c83d4fccf1940e7056d4bc6acae845fe6886a8bf33b5";
const SESSION_KEY = "macclipper-authorized";

async function sha256(input) {
  const bytes = new TextEncoder().encode(input);
  const hash = await crypto.subtle.digest("SHA-256", bytes);
  return Array.from(new Uint8Array(hash)).map(b => b.toString(16).padStart(2, "0")).join("");
}

export default function PasswordGate({ children }) {
  const [authorized, setAuthorized] = useState(!!sessionStorage.getItem(SESSION_KEY));
  const [password, setPassword] = useState("");
  const [error, setError] = useState(false);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (authorized) {
      sessionStorage.setItem(SESSION_KEY, "true");
    }
  }, [authorized]);

  async function handleSubmit(e) {
    e.preventDefault();
    setLoading(true);
    setError(false);
    const hash = await sha256(password);
    if (hash === PASSWORD_HASH) {
      setAuthorized(true);
    } else {
      setError(true);
      setPassword("");
      setLoading(false);
    }
  }

  if (authorized) return children;

  return (
    <div style={{
      position: "fixed", inset: 0, display: "flex", alignItems: "center", justifyContent: "center",
      background: "#0d1117", zIndex: 9999, fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif"
    }}>
      <form onSubmit={handleSubmit} style={{
        background: "#161b22", border: "1px solid #30363d", borderRadius: 12, padding: 40,
        width: 360, boxShadow: "0 8px 32px rgba(0,0,0,0.4)"
      }}>
        <div style={{ textAlign: "center", marginBottom: 28 }}>
          <div style={{
            width: 64, height: 64, borderRadius: 16, background: "linear-gradient(135deg, #58a6ff, #3fb950)",
            display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 16px",
            fontSize: 28, fontWeight: 700, color: "#fff"
          }}>M</div>
          <h1 style={{ color: "#f0f6fc", fontSize: 20, fontWeight: 600, margin: 0 }}>MacClipper</h1>
          <p style={{ color: "#8b949e", fontSize: 14, marginTop: 6 }}>Private access</p>
        </div>
        <input
          type="password" value={password} onChange={e => setError(false) || setPassword(e.target.value)}
          placeholder="Enter site password" autoFocus
          style={{
            width: "100%", padding: "10px 14px", fontSize: 14, borderRadius: 8, border: `1px solid ${error ? "#f85149" : "#30363d"}`,
            background: "#0d1117", color: "#f0f6fc", outline: "none", boxSizing: "border-box"
          }}
        />
        {error && <p style={{ color: "#f85149", fontSize: 12, marginTop: 6 }}>Incorrect password</p>}
        <button type="submit" disabled={!password || loading} style={{
          width: "100%", marginTop: 16, padding: "10px 14px", fontSize: 14, fontWeight: 600,
          borderRadius: 8, border: "none", color: "#fff",
          background: loading ? "#58a6ff80" : !password ? "#21262d" : "#58a6ff",
          cursor: !password || loading ? "not-allowed" : "pointer"
        }}>
          {loading ? "Checking..." : "Enter"}
        </button>
      </form>
    </div>
  );
}
